// IndexedDB wrapper for offline storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;
const STORE_NAME = 'inspections';

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains(STORE_NAME)) {
                const store = database.createObjectStore(STORE_NAME, { keyPath: 'id' });
                store.createIndex('isSynced', 'isSynced', { unique: false });
                store.createIndex('createdAt', 'createdAt', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    saveReport: async function (reportJson) {
        const database = await openDb();
        const report = JSON.parse(reportJson);
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).put(report);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getReport: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).get(id);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllReports: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).getAll();
            request.onsuccess = () => {
                const sorted = request.result.sort((a, b) =>
                    new Date(b.createdAt) - new Date(a.createdAt));
                resolve(JSON.stringify(sorted));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedReports: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const index = tx.objectStore(STORE_NAME).index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteReport: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    markAsSynced: async function (ids) {
        const database = await openDb();
        const idList = JSON.parse(ids);
        const tx = database.transaction(STORE_NAME, 'readwrite');
        const store = tx.objectStore(STORE_NAME);
        for (const id of idList) {
            const request = store.get(id);
            request.onsuccess = () => {
                const report = request.result;
                if (report) {
                    report.isSynced = true;
                    report.syncedAt = new Date().toISOString();
                    store.put(report);
                }
            };
        }
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const index = tx.objectStore(STORE_NAME).index('isSynced');
            const request = index.count(false);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

// Connectivity detection
window.connectivityHelper = {
    isOnline: function () {
