namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly InspectionStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; }
    public bool IsSyncing { get; private set; }
    public int PendingCount { get; private set; }
    public string? LastSyncError { get; private set; }

    public SyncService(InspectionStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityHelper.isOnline");
        await _js.InvokeVoidAsync("connectivityHelper.registerOnlineHandler", _dotNetRef);
        await UpdatePendingCountAsync();

        // Attempt sync every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke();

        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline || IsSyncing) return;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke();

            var unsynced = await _storage.GetUnsyncedReportsAsync();
            if (unsynced.Count == 0)
            {
                LastSyncError = null;
                return;
            }

            var request = new SyncRequest { Reports = unsynced };
            var response = await _http.PostAsJsonAsync("/api/inspections/sync", request);

            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResponse>();
                if (result?.AcceptedIds.Count > 0)
                {
                    await _storage.MarkAsSyncedAsync(result.AcceptedIds);
                }
                LastSyncError = null;
            }
            else
            {
                LastSyncError = $"Server returned {response.StatusCode}";
            }
        }
        catch (Exception ex)
        {
            LastSyncError = ex.Message;
            // Swallow - will retry on next interval
        }
        finally
        {
            IsSyncing = false;
            await UpdatePendingCountAsync();
            OnSyncStatusChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCountAsync()
    {
        try
        {
            PendingCount = await _storage.GetUnsyncedCountAsync();
        }
        catch { /* IndexedDB might not be ready yet */ }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _dotNetRef?.Dispose();
    }
}

// IndexedDB wrapper for offline storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;
const STORE_NAME = 'inspections';

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains(STORE_NAME)) {
                const store = database.createObjectStore(STORE_NAME, { keyPath: 'id' });
                store.createIndex('isSynced', 'isSynced', { unique: false });
                store.createIndex('createdAt', 'createdAt', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbStorage = {
    saveReport: async function (reportJson) {
        const database = await openDb();
        const report = JSON.parse(reportJson);
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).put(report);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getReport: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).get(id);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllReports: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const request = tx.objectStore(STORE_NAME).getAll();
            request.onsuccess = () => {
                const sorted = request.result.sort((a, b) =>
                    new Date(b.createdAt) - new Date(a.createdAt));
                resolve(JSON.stringify(sorted));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedReports: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const index = tx.objectStore(STORE_NAME).index('isSynced');
            const request = index.getAll(false);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteReport: async function (id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            tx.objectStore(STORE_NAME).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    markAsSynced: async function (ids) {
        const database = await openDb();
        const idList = JSON.parse(ids);
        const tx = database.transaction(STORE_NAME, 'readwrite');
        const store = tx.objectStore(STORE_NAME);
        for (const id of idList) {
            const request = store.get(id);
            request.onsuccess = () => {
                const report = request.result;
                if (report) {
                    report.isSynced = true;
                    report.syncedAt = new Date().toISOString();
                    store.put(report);
                }
            };
        }
        return new Promise((resolve, reject) => {
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const index = tx.objectStore(STORE_NAME).index('isSynced');
            const request = index.count(false);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

