namespace SiteInspector.Client.Services;

public class SyncService : IDisposable
{
    private readonly InspectionStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; }
    public bool IsSyncing { get; private set; }
    public int PendingCount { get; private set; }
    public string? LastSyncError { get; private set; }

    public SyncService(InspectionStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityHelper.isOnline");
        await _js.InvokeVoidAsync("connectivityHelper.registerOnlineHandler", _dotNetRef);
        await UpdatePendingCountAsync();

        // Attempt sync every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke();

        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline || IsSyncing) return;

        try
        {
            IsSyncing = true;
            OnSyncStatusChanged?.Invoke();

            var unsynced = await _storage.GetUnsyncedReportsAsync();
            if (unsynced.Count == 0)
            {
                LastSyncError = null;
                return;
            }

            var request = new SyncRequest { Reports = unsynced };
            var response = await _http.PostAsJsonAsync("/api/inspections/sync", request);

            if (response.IsSuccessStatusCode)
            {
                var result = await response.Content.ReadFromJsonAsync<SyncResponse>();
                if (result?.AcceptedIds.Count > 0)
                {
                    await _storage.MarkAsSyncedAsync(result.AcceptedIds);
                }
                LastSyncError = null;
            }
            else
            {
                LastSyncError = $"Server returned {response.StatusCode}";
            }
        }
        catch (Exception ex)
        {
            LastSyncError = ex.Message;
        }
        finally
        {
            IsSyncing = false;
            await UpdatePendingCountAsync();
            OnSyncStatusChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCountAsync()
    {
        try
        {
            PendingCount = await _storage.GetUnsyncedCountAsync();
        }
        catch { /* IndexedDB might not be ready yet */ }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _dotNetRef?.Dispose();
    }
}

