@page "/inspection/{Id}"

@using SiteInspector.Shared

<div class="inspection-page">
    <header class="inspection-header">
        <a href="/" class="back-btn">← Back</a>
        <h1>@(_isNew ? "New Inspection" : "Edit Inspection")</h1>
        <button class="btn-save" @onclick="SaveReport">💾 Save</button>
    </header>

    @if (_report == null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="form-section">
            <label>Site Name</label>
            <input type="text" @bind="_report.SiteName" @bind:event="oninput"
                   placeholder="e.g. Block A - Level 3" class="input-field" />

            <label>Inspector Name</label>
            <input type="text" @bind="_report.InspectorName" @bind:event="oninput"
                   placeholder="Your name" class="input-field" />
        </div>

        <!-- Checklist Section -->
        <div class="checklist-section">
            <h2>Safety Checklist</h2>

            @foreach (var category in _report.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="category-group">
                    <h3 class="category-title">@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <span class="item-desc">@item.Description</span>
                            <div class="item-actions">
                                <button class="status-btn pass @(item.Status == CheckStatus.Pass ? "active" : "")"
                                        @onclick="() => SetStatus(item, CheckStatus.Pass)">✓</button>
                                <button class="status-btn fail @(item.Status == CheckStatus.Fail ? "active" : "")"
                                        @onclick="() => SetStatus(item, CheckStatus.Fail)">✗</button>
                                <button class="status-btn na @(item.Status == CheckStatus.NotApplicable ? "active" : "")"
                                        @onclick="() => SetStatus(item, CheckStatus.NotApplicable)">N/A</button>
                            </div>
                            @if (item.Status == CheckStatus.Fail)
                            {
                                <input type="text" @bind="item.Notes" @bind:event="oninput"
                                       placeholder="Note required for failures..."
                                       class="item-note" />
                            }
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Notes Section -->
        <div class="form-section">
            <h2>General Notes</h2>
            <textarea @bind="_report.Notes" @bind:event="oninput"
                      placeholder="Additional observations, concerns, or recommendations..."
                      rows="4" class="input-field textarea"></textarea>
        </div>

        <!-- Photos Section -->
        <div class="photos-section">
            <h2>Photos (@_report.Photos.Count)</h2>

            <input type="file" id="photoInput" accept="image/*" capture="environment"
                   style="display:none" @onchange="OnPhotoSelected" @ref="_fileInput" />
            <button class="btn-photo" @onclick="TriggerPhotoCapture">📷 Add Photo</button>

            @if (_report.Photos.Count > 0)
            {
                <div class="photo-grid">
                    @foreach (var photo in _report.Photos)
                    {
                        <div class="photo-card">
                            <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                            <input type="text" @bind="photo.Caption" @bind:event="oninput"
                                   placeholder="Caption..." class="photo-caption" />
                            <button class="btn-remove-photo" @onclick="() => RemovePhoto(photo)">🗑️</button>
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Save Button (bottom) -->
        <div class="bottom-actions">
            <button class="btn-primary btn-large" @onclick="SaveReport">
                💾 Save Inspection
            </button>
            @if (_saved)
            {
                <span class="save-confirmation">✅ Saved locally!</span>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string? Id { get; set; }
    [Inject] private InspectionStorageService Storage { get; set; } = default!;
    [Inject] private NavigationManager Nav { get; set; } = default!;
    [Inject] private IJSRuntime JS { get; set; } = default!;

    private InspectionReport? _report;
    private bool _isNew;
    private bool _saved;
    private ElementReference _fileInput;

    protected override async Task OnInitializedAsync()
    {
        if (Id == null || Id == "new")
        {
            _isNew = true;
            _report = new InspectionReport
            {
                ChecklistItems = ChecklistTemplates.GetStandardSafetyChecklist()
            };
        }
        else
        {
            _report = await Storage.GetReportAsync(Id);
            if (_report == null)
            {
                Nav.NavigateTo("/");
            }
        }
    }

    private void SetStatus(ChecklistItem item, CheckStatus status)
    {
        item.Status = (item.Status == status) ? CheckStatus.NotChecked : status;
    }

    private string GetItemClass(ChecklistItem item) => item.Status switch
    {
        CheckStatus.Pass => "item-pass",
        CheckStatus.Fail => "item-fail",
        CheckStatus.NotApplicable => "item-na",
        _ => ""
    };

    private async Task SaveReport()
    {
        if (_report == null) return;
        _report.IsSynced = false;
        await Storage.SaveReportAsync(_report);
        _saved = true;
        _isNew = false;
        StateHasChanged();

        // Auto-hide confirmation after 2s
        _ = Task.Delay(2000).ContinueWith(_ =>
        {
            _saved = false;
            InvokeAsync(StateHasChanged);
        });
    }

    private async Task TriggerPhotoCapture()
    {
        await JS.InvokeVoidAsync("eval", "document.getElementById('photoInput').click()");
    }

    private async Task OnPhotoSelected()
    {
        var json = await JS.InvokeAsync<string>("cameraHelper.capturePhoto", "photoInput");
        if (!string.IsNullOrEmpty(json))
        {
            var data = System.Text.Json.JsonSerializer.Deserialize<PhotoData>(json);
            if (data != null && _report != null)
            {
                _report.Photos.Add(new PhotoAttachment
                {
                    FileName = data.FileName,
                    ContentType = data.ContentType,
                    Base64Data = data.Base64Data
                });
            }
        }
    }

    private void RemovePhoto(PhotoAttachment photo)
    {
        _report?.Photos.Remove(photo);
    }

    private record PhotoData(string FileName, string ContentType, string Base64Data);
}

