@page "/"

<div class="dashboard">
    <h1 class="page-title">🏗️ Site Inspector</h1>

    <div class="status-bar">
        <span class="connectivity @(SyncSvc.IsOnline ? "online" : "offline")">
            @(SyncSvc.IsOnline ? "● Online" : "● Offline")
        </span>
        @if (SyncSvc.PendingCount > 0)
        {
            <span class="pending-badge">@SyncSvc.PendingCount pending sync</span>
        }
    </div>

    <a href="/inspection/new" class="btn-primary btn-large">
        ➕ New Inspection
    </a>

    @if (SyncSvc.PendingCount > 0 && SyncSvc.IsOnline)
    {
        <button class="btn-sync" @onclick="SyncNow" disabled="@SyncSvc.IsSyncing">
            @(SyncSvc.IsSyncing ? "⏳ Syncing..." : "🔄 Sync Now")
        </button>
    }

    <h2 class="section-title">Recent Inspections</h2>

    @if (_reports == null)
    {
        <p class="loading">Loading...</p>
    }
    else if (_reports.Count == 0)
    {
        <p class="empty-state">No inspections yet. Tap "New Inspection" to get started.</p>
    }
    else
    {
        <div class="report-list">
            @foreach (var report in _reports)
            {
                <a href="/inspection/@report.Id" class="report-card">
                    <div class="report-header">
                        <strong>@report.SiteName</strong>
                        <span class="sync-icon">@(report.IsSynced ? "✅" : "⏳")</span>
                    </div>
                    <div class="report-meta">
                        <span>@report.InspectorName</span>
                        <span>@report.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                    </div>
                    <div class="report-stats">
                        @{
                            var passed = report.ChecklistItems.Count(c => c.Status == SiteInspector.Shared.CheckStatus.Pass);
                            var failed = report.ChecklistItems.Count(c => c.Status == SiteInspector.Shared.CheckStatus.Fail);
                            var total = report.ChecklistItems.Count;
                        }
                        <span class="stat pass">✓ @passed</span>
                        <span class="stat fail">✗ @failed</span>
                        <span class="stat total">/@total items</span>
                        @if (report.Photos.Count > 0)
                        {
                            <span class="stat photos">📷 @report.Photos.Count</span>
                        }
                    </div>
                </a>
            }
        </div>
    }
</div>

@code {
    [Inject] private InspectionStorageService Storage { get; set; } = default!;
    [Inject] private SyncService SyncSvc { get; set; } = default!;

    private List<SiteInspector.Shared.InspectionReport>? _reports;

    protected override async Task OnInitializedAsync()
    {
        SyncSvc.OnSyncStatusChanged += StateHasChanged;
        _reports = await Storage.GetAllReportsAsync();
    }

    private async Task SyncNow()
    {
        await SyncSvc.TrySyncAsync();
        _reports = await Storage.GetAllReportsAsync();
    }
}

