cat > /tmp/sv-b93054f892dd4d1dbf3ced2c04142a02/SiteInspector.Client/wwwroot/css/app.css << 'EOF'
/* Mobile-first CSS for Site Inspector */
:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --success: #34a853;
    --danger: #ea4335;
    --warning: #fbbc04;
    --neutral: #5f6368;
    --bg: #f8f9fa;
    --card-bg: #ffffff;
    --text: #202124;
    --text-secondary: #5f6368;
    --border: #dadce0;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.08);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    line-height: 1.5;
    background: var(--bg);
    color: var(--text);
    -webkit-font-smoothing: antialiased;
    overscroll-behavior: none;
}

.app-container {
    max-width: 768px;
    margin: 0 auto;
    padding: 0;
    min-height: 100vh;
}

main {
    padding: 16px;
    padding-bottom: 80px;
}

/* Loading */
.loading-screen {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 100vh;
    gap: 8px;
}

/* Dashboard */
.page-title {
    font-size: 1.5rem;
    margin: 0 0 12px 0;
}

.status-bar {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
    padding: 8px 12px;
    background: var(--card-bg);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
}

.connectivity {
    font-weight: 600;
    font-size: 0.875rem;
}
.connectivity.online { color: var(--success); }
.connectivity.offline { color: var(--danger); }

.pending-badge {
    font-size: 0.8rem;
    background: var(--warning);
    color: #000;
    padding: 2px 8px;
    border-radius: 12px;
    font-weight: 500;
}

.section-title {
    font-size: 1.1rem;
    margin: 20px 0 12px 0;
    color: var(--text-secondary);
}

/* Buttons */
.btn-primary {
    display: block;
    width: 100%;
    padding: 16px;
    background: var(--primary);
    color: white;
    border: none;
    border-radius: var(--radius);
    font-size: 1.1rem;
    font-weight: 600;
    text-align: center;
    text-decoration: none;
    cursor: pointer;
    transition: background 0.15s;
    touch-action: manipulation;
}
.btn-primary:hover, .btn-primary:active {
    background: var(--primary-dark);
    color: white;
    text-decoration: none;
}
.btn-large {
    padding: 18px;
    font-size: 1.2rem;
}

.btn-sync {
    display: block;
    width: 100%;
    margin-top: 8px;
    padding: 12px;
    background: var(--card-bg);
    border: 2px solid var(--primary);
    border-radius: var(--radius);
    color: var(--primary);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    touch-action: manipulation;
}

.btn-save {
    padding: 8px 16px;
    background: var(--success);
    color: white;
    border: none;
    border-radius: 8px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    touch-action: manipulation;
}

.btn-photo {
    display: block;
    width: 100%;
    padding: 14px;
    background: var(--card-bg);
    border: 2px dashed var(--border);
    border-radius: var(--radius);
    font-size: 1rem;
    cursor: pointer;
    text-align: center;
    touch-action: manipulation;
}

/* Report Cards */
.report-list {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.report-card {
    display: block;
    padding: 14px 16px;
    background: var(--card-bg);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    text-decoration: none;
    color: var(--text);
    transition: transform 0.1s;
    touch-action: manipulation;
}
.report-card:active {
    transform: scale(0.98);
}

.report-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 4px;
}

.report-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: var(--text-secondary);
    margin-bottom: 6px;
}

.report-stats {
    display: flex;
    gap: 10px;
    font-size: 0.85rem;
}
.stat.pass { color: var(--success); font-weight: 600; }
