arguments.new_str:
using Microsoft.EntityFrameworkCore;
using SiteInspector.Shared;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddDbContext<InspectionDbContext>(options =>
    options.UseSqlite("Data Source=inspections.db"));
builder.Services.AddCors(options =>
    options.AddDefaultPolicy(policy =>
        policy.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));

var app = builder.Build();

// Ensure database is created
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<InspectionDbContext>();
    db.Database.EnsureCreated();
}

app.UseCors();

// Serve the Blazor WASM client
app.UseStaticFiles();
app.UseBlazorFrameworkFiles();

// Sync endpoint - receives inspection reports from offline clients
app.MapPost("/api/inspections/sync", async (SyncRequest request, InspectionDbContext db) =>
{
    var response = new SyncResponse();

    foreach (var report in request.Reports)
    {
        try
        {
            var existing = await db.Inspections.FindAsync(report.Id);
            if (existing != null)
            {
                // Update existing
                existing.SiteName = report.SiteName;
                existing.InspectorName = report.InspectorName;
                existing.Notes = report.Notes;
                existing.ChecklistJson = System.Text.Json.JsonSerializer.Serialize(report.ChecklistItems);
                existing.PhotosJson = System.Text.Json.JsonSerializer.Serialize(report.Photos);
                existing.SyncedAt = DateTime.UtcNow;
            }
            else
            {
                db.Inspections.Add(new InspectionEntity
                {
